30	const BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	  moonstone: 25,
37	};
38	
39	const PROCESSING_FEE = 5;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	const BLOCK_SIZE = 3;
42	const BLOCK_PREMIUM = 60;
43	
44	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
45	
46	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
47	
48	const FIRST_INSURANCE_RATE = 0.1;
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const LOYALTY_YEARS_THRESHOLD = 2;
51	const CURSED_SURCHARGE_RATE = 0.5;
52	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
53	const HIGH_ENCHANTMENT_THRESHOLD = 5;
54	
55	const itemSurcharge = (item: Item): number => {
56	  const base = basePremium(item);
57	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
58	  const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
59	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
60	    : 0;
61	  return cursedSurcharge + enchantmentSurcharge;
62	};
63	
64	const countByType = (items: Item[]): Map<string, number> => {
65	  const counts = new Map<string, number>();
66	  for (const item of items) {
67	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  }
69	  return counts;
70	};
71	
72	const calculateComponentPremiums = (components: Item[]): number => {
73	  let total = 0;
74	  for (const [type, count] of countByType(components)) {
75	    total += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
76	  }
77	  return total;
